 @return: The value for a key that appears in the lzoptions string

This service represents a style sheet
 Source: http://www.w3.org/TR/DOM-Level-2-Style/stylesheets.html#StyleSheets-StyleSheet
 Introduced in DOM Level 2:
 interface StyleSheet {
   readonly attribute DOMString        type;
            attribute boolean          disabled;
   readonly attribute Node             ownerNode;
   readonly attribute StyleSheet       parentStyleSheet;
   readonly attribute DOMString        href;
   readonly attribute DOMString        title;
   readonly attribute MediaList        media;
 };

This service represents a CSS Style sheet
 Introduced in DOM Level 2:
 interface CSSStyleSheet : stylesheets::StyleSheet {
 readonly attribute CSSRule          ownerRule;
 readonly attribute CSSRuleList      cssRules;
 unsigned long      insertRule(in DOMString rule, 
 in unsigned long index)
 raises(DOMException);
  void               deleteRule(in unsigned long index)
                                        raises(DOMException);
 };
